ActorScope.description:
Closed scope-membership tuple (Tenant -> Organization -> Workspace -> Environment) per VISION Â§V and ADR 0068 D-2 (Proposed). Reused from `actor.schema.json#/$defs/ActorScope` so the wire shape stays canonical across actor identity, scope-context reads, and scope-swap requests (ADR 0082 D-14 â€” never redefine).

 <details><summary>JSON schema</summary>

 ```json
{
  "description": "Closed scope-membership tuple (Tenant -> Organization -> Workspace -> Environment) per VISION Â§V and ADR 0068 D-2 (Proposed). Reused from `actor.schema.json#/$defs/ActorScope` so the wire shape stays canonical across actor identity, scope-context reads, and scope-swap requests (ADR 0082 D-14 â€” never redefine).",
  "type": "object",
  "required": [
    "environment",
    "organization",
    "tenant"
  ],
  "properties": {
    "environment": {
      "description": "Closed deployment environment (VISION Â§V). `sandbox` = dev/test; `staging` = pre-prod; `prod` = live. New environments require a major schema bump.",
      "enum": [
        "sandbox",
        "staging",
        "prod"
      ]
    },
    "organization": {
      "description": "Organization identifier â€” product-ownership boundary where forms, cases, and members live (VISION Â§V; ADR 0068 D-1 (Proposed)). Object-ownership and deletion-follows-org invariants tie retention to this id, not to billing state.",
      "examples": [
        "org-state-of-x-dhss"
      ],
      "type": "string",
      "minLength": 1,
      "x-wos": {
        "openStringKind": "identifier"
      }
    },
    "tenant": {
      "description": "Tenant identifier â€” outermost hosting/commercial boundary (VISION Â§V; ADR 0068 D-1 (Proposed)). Hosting-tier identity, not user-visible.",
      "examples": [
        "tenant-acme",
        "tenant-formspec-public"
      ],
      "type": "string",
      "minLength": 1,
      "x-wos": {
        "openStringKind": "identifier"
      }
    },
    "workspace": {
      "description": "Optional workspace identifier â€” sub-scope inside an organization (VISION Â§V). Omitted when the actor is bound at the organization level.",
      "examples": [
        "workspace-snap-eligibility"
      ],
      "type": "string",
      "minLength": 1,
      "x-wos": {
        "openStringKind": "identifier"
      }
    }
  },
  "additionalProperties": false
}
 ```
 </details>

