  "description": "Single assertion-gate evaluation result (governance Â§5.4; workflow-governance.md:293-305). Each pipeline stage's gate evaluation produces one of these â€” closed-taxonomy gate kind + pass/fail boolean + structured evidence references. Embedded as an optional array on `ReasoningTierRecord.assertionGates` so an auditor walking the reasoning trace can answer \"which gate kind failed at this stage and what evidence backs the failure?\" without re-deriving from open-prose `criteriaChecked.detail`.",
  "type": "object",
  "required": [
    "gateKind",
    "gatePassed"
  ],
  "properties": {
    "detail": {
      "description": "Optional human-readable detail explaining the gate result. Free-form prose for cases where the structured evidence does not carry the full story.",
      "type": "string",
      "minLength": 1,
      "x-wos": {
        "openStringKind": "prose"
      }
    },
    "evidenceRefs": {
      "description": "Structured evidence references supporting the gate's pass/fail finding (governance Â§5.4 â€” \"each gate produces a pass/fail result with structured evidence\"). Empty when the gate verification did not surface specific evidence references (typical for `format` parse checks); populated for `source-grounded`, `cross-document`, and `consistency` gates whose evidence is referenceable.",
      "type": "array",
      "items": {
        "$ref": "#/$defs/EvidenceReference"
      }
    },
    "gateKind": {
      "description": "Closed-with-vendor-extension classification of which Â§5.4 gate produced this result.",
      "$ref": "#/$defs/AssertionGateKind"
