AuditAttestationView.description:
Projected identity-attestation chain view for a single subject across cases. Aggregates `IdentityAttestation` Facts-tier records (Kernel S8 / ADR 0068 D-3.1) so an investigator can answer 'what attestations did this subject hold, by which provider, with what assurance, when?' without enumerating cases by hand. Gates on PLN-0381 (stack identity-attestation ADR) â€” the projection shape is authored against the proposed `IdentityAttestation` record from ADR 0068 D-3.1; the wire form ratifies when PLN-0381 lands. Until then, servers MAY return only the fields they have settled and clients tolerate field absence.

 <details><summary>JSON schema</summary>

 ```json
{
  "description": "Projected identity-attestation chain view for a single subject across cases. Aggregates `IdentityAttestation` Facts-tier records (Kernel S8 / ADR 0068 D-3.1) so an investigator can answer 'what attestations did this subject hold, by which provider, with what assurance, when?' without enumerating cases by hand. Gates on PLN-0381 (stack identity-attestation ADR) â€” the projection shape is authored against the proposed `IdentityAttestation` record from ADR 0068 D-3.1; the wire form ratifies when PLN-0381 lands. Until then, servers MAY return only the fields they have settled and clients tolerate field absence.",
  "type": "object",
  "required": [
    "attestations",
    "subjectGlobalId"
  ],
  "properties": {
    "attestations": {
      "description": "The chain of identity-attestation records observed for this subject within the queried scope, ordered by `attestedAt` ascending. Each entry is a Facts-tier `ProvenanceRecord` whose `recordKind == identityAttestation` (cross-`$ref`ed; the audit projection is the per-case shape).",
      "type": "array",
      "items": {
        "$ref": "#/$defs/FactsTierRecord"
      }
    },
    "earliestAttestedAt": {
      "description": "UTC RFC 3339 timestamp of the earliest attestation in the chain. Omitted when the chain is empty.",
      "type": "string",
      "format": "date-time"
    },
    "highestAssuranceLevel": {
      "description": "Highest assurance level observed across the attestation chain (closed taxonomy from ADR 0068 D-3.1 + vendor-prefix extension per ADR 0082 D-12). Mirrors `wos-workflow.schema.json` `IdentityAttestationRecord.assuranceLevel`. Computed by the server from the chain; useful for compliance investigators answering 'did this subject ever reach high assurance under this provider?'.",
      "oneOf": [
        {
          "enum": [
            "low",
            "standard",
            "high",
            "very-high"
          ]
        },
        {
          "type": "string",
          "pattern": "^x-[a-z][a-z0-9-]*$"
        }
      ],
      "x-wos": {
        "assuranceTaxonomyMapping": {
          "L1": "low",
          "L2": "standard",
          "L3": "high",
          "L4": "very-high"
        },
        "note": "The wire vocabulary (low/standard/high/very-high) is shared with wos-workflow.schema.json identity-attestation shapes. The assurance prose (assurance.md Â§2.1) uses L1-L4. This mapping is the canonical cross-reference. A future taxonomy unification (ADR TBD) will align them."
      }
    },
    "latestAttestedAt": {
      "description": "UTC RFC 3339 timestamp of the most-recent attestation in the chain. Omitted when the chain is empty.",
      "type": "string",
      "format": "date-time"
    },
    "subjectGlobalId": {
      "description": "Tenant-independent subject identifier (URI; e.g., `did:web:...`, `urn:idp:subject:...`) per ADR 0068 D-3.1. The view aggregates every `IdentityAttestation` record naming this subject across visible cases.",
      "examples": [
        "did:web:identity.example.gov:caseworker-17",
        "urn:idp:subject:0a1b2c3d"
      ],
      "type": "string",
      "format": "uri",
      "minLength": 1,
      "x-wos": {
        "openStringKind": "uri"
      }
    }
  },
  "additionalProperties": false
}
 ```
