AuditQueryRequest.description:
Cross-case audit query request body for `POST /api/v1/audit/queries`. Submits a parameterised query against the cross-case provenance corpus and (when `materialize: true`) requests durable result storage so a long-running query can be polled and paginated. The query envelope is closed: every filter is named and scoped; there is no open `criteria: Record<string, unknown>` bag.

 <details><summary>JSON schema</summary>

 ```json
{
  "description": "Cross-case audit query request body for `POST /api/v1/audit/queries`. Submits a parameterised query against the cross-case provenance corpus and (when `materialize: true`) requests durable result storage so a long-running query can be polled and paginated. The query envelope is closed: every filter is named and scoped; there is no open `criteria: Record<string, unknown>` bag.",
  "type": "object",
  "required": [
    "scope"
  ],
  "properties": {
    "actorRef": {
      "description": "Optional actor URN filter â€” restrict the query to records whose `actorRef` equals this principal (ADR 0082 D-9). Identity-attestation investigations use this filter against a specific subject.",
      "$ref": "#/$defs/ActorRef"
    },
    "instanceScope": {
      "description": "Optional instance scope â€” restrict the result set to records belonging to one or more named workflow processes. Empty array is forbidden. When omitted the query spans every visible instance in scope.",
      "type": "array",
      "items": {
        "$ref": "#/$defs/WosResourceUrn"
      },
      "minItems": 1,
      "uniqueItems": true
    },
    "materialize": {
      "description": "When true, the server materializes the result set so it can be paginated across multiple GET requests. When false (default), the query executes synchronously and `POST /api/v1/audit/queries` returns the first page directly. `Idempotency-Key` is REQUIRED when `materialize: true` (ADR 0082 D-16) because materialization is an externally-visible side effect.",
      "type": "boolean"
    },
    "maxResults": {
      "description": "Hard upper bound on the result set, applied after every other filter. Servers MAY enforce a smaller per-deployment ceiling. The page size is governed by `limit` on the result endpoints; this bound caps the total result corpus the query materializes.",
      "type": "integer",
      "maximum": 100000.0,
      "minimum": 1.0
    },
    "recordKindFilter": {
      "description": "Optional record-kind filter â€” restrict the result set to one or more Facts-tier `recordKind` literals (e.g., `identityAttestation`, `signatureAffirmation`, `caseStateMutation`). Cross-`$ref`s the closed-with-vendor-extension `FactsRecordKind` taxonomy from `provenance.schema.json`.",
      "examples": [
        [
          "identityAttestation"
        ],
        [
          "signatureAffirmation",
          "stateTransition"
        ]
      ],
      "type": "array",
      "items": {
        "$ref": "#/$defs/FactsRecordKind"
      },
      "minItems": 1,
      "uniqueItems": true
    },
    "scope": {
      "description": "Tenant / Organization / Workspace / Environment scope (ADR 0068 D-2 Proposed). Tenant is REQUIRED; cross-tenant queries are refused at the runtime.",
      "$ref": "#/$defs/AuditScopeFilter"
    },
    "sort": {
      "description": "Result-set ordering. Defaults to `timestamp-desc` when omitted.",
      "$ref": "#/$defs/AuditQuerySort"
    },
    "tierFilter": {
      "description": "Optional tier filter â€” restrict the result set to one or more provenance tiers. Empty array is forbidden; omit the field to span all four tiers.",
      "examples": [
        [
          "facts"
        ],
        [
          "reasoning",
          "counterfactual"
        ]
      ],
      "type": "array",
      "items": {
        "$ref": "#/$defs/AuditTierFilter"
      },
      "minItems": 1,
      "uniqueItems": true
    },
    "timeRange": {
      "description": "Optional UTC RFC 3339 time-range filter against the provenance record `timestamp` field. Omitted to span the full retention window.",
      "type": "object",
      "required": [
        "end",
        "start"
      ],
      "properties": {
        "end": {
          "description": "Inclusive UTC RFC 3339 upper bound for the audit window.",
          "type": "string",
          "format": "date-time"
        },
        "start": {
          "description": "Inclusive UTC RFC 3339 lower bound for the audit window.",
          "type": "string",
          "format": "date-time"
        }
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}
 ```
 </details>

