      "type": "number",
      "maximum": 1.0,
      "minimum": 0.0
    },
    "cumulativeConfidenceWindow": {
      "description": "Rolling cumulative-confidence state (ai-integration.md Â§7.7; ai-integration.md:475-477 â€” \"the cumulative confidence after step n is the product of individual step confidences by default\"). Lets a reviewer query \"is this multi-step session below the confidence floor?\" without re-deriving the product.",
      "type": "object",
