          "type": "boolean"
        },
        "cumulativeConfidence": {
          "description": "Product of per-step confidences in [0,1]. When this falls below the workflow's `confidenceFloor`, the Â§7.7 MUST requires the interaction to pause for human review.",
          "type": "number",
          "maximum": 1.0,
          "minimum": 0.0
