      "$ref": "#/$defs/MessageChannel"
    },
    "contentRef": {
      "description": "Claim-check pointer to the message payload (rendered notice PDF, scanned mail image, email blob, transcript, etc.).",
      "$ref": "#/$defs/ContentRef"
