CorrespondenceRendering.description:
Result of rendering a delivery-sidecar notification template. Renderings are server-stamped, content-addressable artifacts; producing one does not by itself send a correspondence message. A subsequent `POST /api/v1/correspondence` may reference this rendering's URN via `renderingId` to commit it as a sent outbound message.

 <details><summary>JSON schema</summary>

 ```json
{
  "description": "Result of rendering a delivery-sidecar notification template. Renderings are server-stamped, content-addressable artifacts; producing one does not by itself send a correspondence message. A subsequent `POST /api/v1/correspondence` may reference this rendering's URN via `renderingId` to commit it as a sent outbound message.",
  "type": "object",
  "required": [
    "category",
    "deliveryChannels",
    "id",
    "missingVariables",
    "rendered",
    "renderedAt",
    "resolvedVariables",
    "sections",
    "subject",
    "templateRef",
    "workflowUrl"
  ],
  "properties": {
    "category": {
      "description": "Template category resolved from the delivery sidecar (drives due-process validation for adverse-decision notices).",
      "$ref": "#/$defs/RenderingCategory"
    },
    "deliveryChannels": {
      "description": "Delivery channels declared by the source template, projected through the closed `DeliveryChannelKind` enum.",
      "type": "array",
      "items": {
        "$ref": "#/$defs/DeliveryChannelKind"
      },
      "minItems": 1,
      "uniqueItems": true
    },
    "id": {
      "description": "Stable URN for this rendering.",
      "$ref": "#/$defs/WosResourceUrn"
    },
    "missingVariables": {
      "description": "Sorted, deduplicated names of required template variables that were not resolved. When non-empty the rendering is advisory only and MUST NOT be referenced by a subsequent `LogCorrespondenceMessageRequest`; the server returns `WOS-1422` if a caller attempts to do so.",
      "type": "array",
      "items": {
        "description": "Name of a template placeholder variable required by the template but not supplied or resolvable from case state.",
        "type": "string",
        "pattern": "^[A-Za-z][A-Za-z0-9_]{0,63}$"
      },
      "uniqueItems": true
    },
    "rendered": {
      "description": "Concatenated full-document rendering (sections joined with newlines) for clients that only need a single body string. Always present even when sections are empty post-condition (renders to the empty string).",
      "type": "string",
      "x-wos": {
        "openStringKind": "prose"
      }
    },
    "renderedAt": {
      "description": "UTC RFC 3339 timestamp when the rendering was produced.",
      "type": "string",
      "format": "date-time"
    },
    "resolvedVariables": {
      "description": "Sorted, deduplicated names of placeholder variables resolved during rendering. Closed shape â€” only variable names, never values.",
      "type": "array",
      "items": {
        "description": "Name of a template placeholder variable that was resolved during rendering.",
        "type": "string",
        "pattern": "^[A-Za-z][A-Za-z0-9_]{0,63}$"
      },
      "uniqueItems": true
    },
    "sections": {
      "description": "Ordered rendered sections after condition evaluation.",
      "type": "array",
      "items": {
        "$ref": "#/$defs/RenderedSection"
      },
      "minItems": 1
    },
    "subject": {
      "description": "Rendered subject line. Empty templates without subjects produce a server-supplied default (e.g., the template description); the field is always present so consumers do not branch on absence.",
      "examples": [
        "Notice of Decision: SNAP Application"
      ],
      "type": "string",
      "minLength": 1,
      "x-wos": {
        "openStringKind": "prose"
      }
    },
    "templateRef": {
      "description": "Notification template key the renderer resolved.",
      "$ref": "#/$defs/TemplateRef"
    },
    "workflowUrl": {
      "description": "Workflow URI whose delivery sidecar supplied the template.",
      "$ref": "#/$defs/WorkflowUrn"
    }
  },
  "additionalProperties": false
}
 ```
 </details>

