TokenIntrospection.description:
Token introspection response returned by `GET /api/v1/auth/introspect` for the bearer token presented on the request. Modeled after RFC 7662 (OAuth 2.0 Token Introspection) with WOS-specific scope and assurance fields. The `active` flag is the load-bearing field: when false, all other fields except possibly `expiresAt` MAY be omitted (the server is asserting the token does not authenticate). Service-account and workload calls (per VISION Â§V) use this endpoint to verify their token's continuing validity without round-tripping a real read.

 <details><summary>JSON schema</summary>

 ```json
{
  "description": "Token introspection response returned by `GET /api/v1/auth/introspect` for the bearer token presented on the request. Modeled after RFC 7662 (OAuth 2.0 Token Introspection) with WOS-specific scope and assurance fields. The `active` flag is the load-bearing field: when false, all other fields except possibly `expiresAt` MAY be omitted (the server is asserting the token does not authenticate). Service-account and workload calls (per VISION Â§V) use this endpoint to verify their token's continuing validity without round-tripping a real read.",
  "type": "object",
  "required": [
    "active"
  ],
  "properties": {
    "active": {
      "description": "True when the bearer token is currently valid (signature verified, not expired, not revoked, not bumped by a global-logout `auth_epoch` rotation). False otherwise.",
      "type": "boolean"
    },
    "actorRef": {
      "description": "URN of the principal the token authenticates. Omitted when `active == false`.",
      "$ref": "#/$defs/ActorRef"
    },
    "assuranceLevel": {
      "description": "Authentication-assurance level attested by this session (ADR 0068 D-3.1 â€” Proposed). Omitted when `active == false`.",
      "$ref": "#/$defs/AuthAssuranceLevel"
    },
    "expiresAt": {
      "description": "UTC RFC 3339 expiry timestamp. Present when `active == true`; MAY be present when `active == false` if the deployment chooses to disclose that the token had expired (rather than been revoked).",
      "type": "string",
      "format": "date-time"
    },
    "issuedAt": {
      "description": "UTC RFC 3339 timestamp when the token was issued.",
      "type": "string",
      "format": "date-time"
    },
    "loginKind": {
      "description": "Credential family used to obtain the original session. Omitted when `active == false`.",
      "$ref": "#/$defs/LoginKind"
    },
    "mfaSatisfied": {
      "description": "True when the session has satisfied a second-factor challenge. Omitted when `active == false`.",
      "type": "boolean"
    },
    "scope": {
      "description": "Active scope tuple bound to the token (ADR 0068 D-2 â€” Proposed). Omitted when `active == false`.",
      "$ref": "#/$defs/ActorScope"
    },
    "tokenKind": {
      "description": "Closed token-kind taxonomy. Always `bearer` at v1. Omitted when `active == false`.",
      "$ref": "#/$defs/TokenKind"
    }
  },
  "additionalProperties": false
}
 ```
 </details>

